#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <cmath>
#include <numeric>

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int M;
    double eps;
    std::cin >> M >> eps;

    // Choose N: balance between separation (needs large N) and score penalty (1/N)
    // SNR for edge matching ≈ N*(1-2eps) / (sqrt(2)*M*sqrt(eps*(1-eps)))
    // Want SNR ≈ 3-4 for reliable decoding
    int N;
    if (eps < 1e-9) {
        N = std::max(4, M);
    } else {
        double noise_factor = std::sqrt(eps * (1.0 - eps)) / std::max(0.05, (1.0 - 2.0 * eps));
        N = (int)std::ceil(4.0 * M * noise_factor);
        N = std::max(N, M);
    }
    N = std::max(4, std::min(100, N));

    int L = N * (N - 1) / 2;

    // Choose k values (number of hubs per graph) with equal-Hamming-distance spacing
    // For k-hub threshold graph: edge (i,j) exists iff i<k or j<k
    // Hamming distance between consecutive k: D(k, k+1) = N-k-1
    // Cumulative distance: T(k) = k*(2N-k-1)/2
    std::vector<int> k_values(M);
    if (M == 1) {
        k_values[0] = N / 2;
    } else {
        double T_max = (double)(N - 1) * N / 2.0;
        for (int i = 0; i < M; i++) {
            double target = (double)i * T_max / (M - 1);
            double disc = (2.0 * N - 1.0) * (2.0 * N - 1.0) - 8.0 * target;
            double k_real = ((2.0 * N - 1.0) - std::sqrt(std::max(0.0, disc))) / 2.0;
            k_values[i] = (int)std::round(k_real);
            k_values[i] = std::max(0, std::min(N - 1, k_values[i]));
        }
        std::sort(k_values.begin(), k_values.end());
        for (int i = 1; i < M; i++) {
            if (k_values[i] <= k_values[i - 1]) {
                k_values[i] = k_values[i - 1] + 1;
            }
        }
        // Handle overflow: fall back to linear spacing
        if (k_values[M - 1] >= N) {
            for (int i = 0; i < M; i++) {
                k_values[i] = (int)std::round((double)i * (N - 1) / (M - 1));
            }
            std::sort(k_values.begin(), k_values.end());
            for (int i = 1; i < M; i++) {
                if (k_values[i] <= k_values[i - 1])
                    k_values[i] = k_values[i - 1] + 1;
            }
            for (int i = 0; i < M; i++) {
                k_values[i] = std::max(0, std::min(N - 1, k_values[i]));
            }
        }
    }

    // Output N and M graphs
    std::cout << N << "\n";
    for (int i = 0; i < M; i++) {
        int k = k_values[i];
        std::string g(L, '0');
        int pos = 0;
        for (int u = 0; u < N; u++) {
            for (int v = u + 1; v < N; v++) {
                if (u < k || v < k) {
                    g[pos] = '1';
                }
                pos++;
            }
        }
        std::cout << g << "\n";
    }
    std::cout.flush();

    // Decode 100 queries using edge-disagreement after degree-based vertex alignment
    // Key insight: instead of comparing N-dimensional degree sequences,
    // we align vertices by degree and count edge mismatches (uses L dimensions).
    // Formula: mismatches(k) = k*(2N-k-1)/2 - E_H + 2*E_out[k]
    // where E_out[k] = edges among the N-k lowest-degree vertices in H.
    std::vector<std::vector<bool>> adj(N, std::vector<bool>(N, false));
    std::vector<int> deg(N, 0);
    std::vector<int> order(N);
    std::vector<int> deg_in_suffix(N, 0);
    std::vector<int> E_out(N + 1, 0);

    for (int q = 0; q < 100; q++) {
        std::string h;
        std::cin >> h;

        int E_H = 0;
        std::fill(deg.begin(), deg.end(), 0);
        int pos = 0;
        for (int u = 0; u < N; u++) {
            for (int v = u + 1; v < N; v++) {
                bool edge = (h[pos] == '1');
                adj[u][v] = adj[v][u] = edge;
                if (edge) {
                    deg[u]++;
                    deg[v]++;
                    E_H++;
                }
                pos++;
            }
        }

        // Sort vertices by degree (descending)
        std::iota(order.begin(), order.end(), 0);
        std::sort(order.begin(), order.end(), [&](int a, int b) {
            return deg[a] > deg[b];
        });

        // Compute deg_in_suffix[j] = edges from order[j] to {order[j+1],...,order[N-1]}
        std::fill(deg_in_suffix.begin(), deg_in_suffix.end(), 0);
        for (int j = 0; j < N; j++) {
            for (int j2 = j + 1; j2 < N; j2++) {
                if (adj[order[j]][order[j2]]) {
                    deg_in_suffix[j]++;
                }
            }
        }

        // Compute E_out[k] = edges among bottom N-k vertices (incrementally)
        E_out[0] = E_H;
        for (int k = 1; k <= N; k++) {
            E_out[k] = E_out[k - 1] - deg_in_suffix[k - 1];
        }

        // Find best candidate minimizing edge disagreements
        int best = 0;
        int best_score = L + 1;
        for (int i = 0; i < M; i++) {
            int k = k_values[i];
            int expected_edges = k * (2 * N - k - 1) / 2;
            int mismatches = expected_edges - E_H + 2 * E_out[k];
            if (mismatches < best_score) {
                best_score = mismatches;
                best = i;
            }
        }

        std::cout << best << "\n";
        std::cout.flush();
    }

    return 0;
}
