// - Edges: k*(2N-k-1)/2
// - Hub vertex has degree N-1
// - Non-hub vertex has degree k
// Hamming distance between k and k+1: N-k-1

// Optimal N selection: maximize E[score] = 0.9^E / N
// where E depends on eps, N, M, and the decoder quality.
// The decoder uses full edge-disagreement matching (L-dimensional signal).

int choose_N(int M, double eps) {
    if (eps < 1e-9) return std::max(4, M + 1);

    // For threshold graphs with equal-T-spacing:
    // Average min Hamming distance ≈ N*(N-1) / (2*(M-1))
    // P(error per query) ≈ M * erfc(sqrt(d_min/2) * (1-2eps) / sqrt(2*eps*(1-eps)*2))
    //
    // Score = 0.9^(100*P_err) / N
    // We want to maximize this over N.

    double best_score = -1;
    int best_N = M + 1;

    for (int N = std::max(4, M + 1); N <= 100; N++) {
        int L = N * (N - 1) / 2;

        // With equal-T-spacing, minimum Hamming distance ≈ sqrt(N*(N-1)/(M-1))
        // More precisely: with k-values chosen for equal T spacing,
        // the minimum distance is approximately N/sqrt(M-1) for moderate M
        // For linear k spacing (k=0..M-1): d_min = N - M (smallest at k=M-2 vs M-1)
        // For equal-T spacing: d_min ≈ (N-1)*N / (2*(M-1)) minimum over gaps
        // Actually with equal T spacing T_max = N*(N-1)/2, step = T_max/(M-1)
        // and d(k) = N-k-1, the minimum distance step corresponds to the largest k value
        // k_max ≈ N - sqrt(N*(N-1)/(M-1)) approximately
        // d_min ≈ sqrt(N*(N-1)/(M-1))

        double d_min;
        if (M <= 2) {
            d_min = L; // only 2 graphs, max separation
        } else {
            d_min = std::sqrt((double)N * (N - 1) / (M - 1));
        }
        d_min = std::max(d_min, 1.0);

        // For the edge-disagreement decoder, the effective noise on the mismatch count
        // follows a binomial distribution. The probability of correct decoding:
        // P_correct ≈ 1 - (M-1)*exp(-d_min*(1-2*eps)^2 / (8*eps*(1-eps)))
        // (union bound over M-1 alternatives)
        double exponent = d_min * (1.0 - 2.0 * eps) * (1.0 - 2.0 * eps) / (8.0 * eps * (1.0 - eps));
        double p_err_per_query = std::min(1.0, (M - 1.0) * std::exp(-exponent));
        double expected_errors = 100.0 * p_err_per_query;
        double score = std::pow(0.9, expected_errors) / N;

        if (score > best_score) {
            best_score = score;
            best_N = N;
        }
    }

    return best_N;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int M;
    double eps;
    std::cin >> M >> eps;

    int N = choose_N(M, eps);
    N = std::max(4, std::min(100, N));
    int L = N * (N - 1) / 2;

