            if (k_values[i] <= k_values[i - 1]) {
                k_values[i] = k_values[i - 1] + 1;
            }
        }
        if (k_values[M - 1] >= N) {
            for (int i = 0; i < M; i++) k_values[i] = i;
        }
    }

    // Output
    std::cout << N << "\n";
    for (int i = 0; i < M; i++) {
        int k = k_values[i];
        std::string g(L, '0');
        int pos = 0;
        for (int u = 0; u < N; u++) {
            for (int v = u + 1; v < N; v++) {
                if (u < k || v < k) g[pos] = '1';
                pos++;
            }
        }
        std::cout << g << "\n";
    }
    std::cout.flush();

    // Decode
    std::vector<int> deg(N, 0);
    std::vector<int> order(N);

    for (int q = 0; q < 100; q++) {
        std::string h;
        std::cin >> h;

        int E_H = 0;
        std::fill(deg.begin(), deg.end(), 0);
        int pos = 0;
        for (int u = 0; u < N; u++) {
            for (int v = u + 1; v < N; v++) {
                if (h[pos] == '1') {
                    deg[u]++;
                    deg[v]++;
                    E_H++;
                }
                pos++;
            }
        }

        // Sort by degree descending
        std::iota(order.begin(), order.end(), 0);
        std::sort(order.begin(), order.end(), [&](int a, int b) {
            return deg[a] > deg[b];
        });

        // Build adjacency for ordered vertices
        std::vector<std::vector<bool>> adj(N, std::vector<bool>(N, false));
        pos = 0;
        for (int u = 0; u < N; u++) {
            for (int v = u + 1; v < N; v++) {
                adj[u][v] = adj[v][u] = (h[pos] == '1');
                pos++;
            }
        }

        // Compute E_out[k] incrementally
        std::vector<int> deg_in_suffix(N, 0);
        for (int j = 0; j < N; j++) {
            for (int j2 = j + 1; j2 < N; j2++) {
                if (adj[order[j]][order[j2]]) {
                    deg_in_suffix[j]++;
                }
            }
        }

        std::vector<int> E_out(N + 1, 0);
        E_out[0] = E_H;
        for (int k = 1; k <= N; k++) {
            E_out[k] = E_out[k - 1] - deg_in_suffix[k - 1];
        }

        // Find best candidate
        int best = 0;
        int best_mismatch = L + 1;
        for (int i = 0; i < M; i++) {
            int k = k_values[i];
            int expected_edges = k * (2 * N - k - 1) / 2;
            int mismatches = expected_edges - E_H + 2 * E_out[k];
            if (mismatches < best_mismatch) {
                best_mismatch = mismatches;
                best = i;
            }
        }

        std::cout << best << "\n";
        std::cout.flush();
    }

    return 0;
}
