    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int M;
    double eps;
    std::cin >> M >> eps;

    // For threshold graphs with k hubs: edges = k*(2N-k-1)/2
    // Key: need N >= M+1 (so M distinct k-values 0..M-1 fit in 0..N-1)
    // Score = 0.9^E / N, so we want smallest N that gives good accuracy.
    //
    // Minimum Hamming distance between consecutive k-values (linear spacing):
    //   d_min ≈ (N-1) for adjacent k values near extremes,
    //   or more precisely: for k vs k+1, d = N - k - 1
    //   With equal-T-spacing we get roughly d_min ≈ N*(N-1)/(2*(M-1)^?)
    //
    // Strategy: Use N just large enough to fit M values with reasonable separation.
    // For threshold graphs with equal-T-spacing:
    //   The minimum Hamming distance is approximately N/sqrt(M-1)
    //   We need d_min > some threshold based on eps for reliable decoding
    //   At eps, expected # flips = L*eps, std = sqrt(L*eps*(1-eps))
    //   For correct decoding: d_min/2 > expected noise ≈ several * std of noise on that distance
    //   More precisely: P(error) ∝ exp(-d_min*(1-2eps)^2 / (8*eps*(1-eps)))
    //   We want d_min*(1-2eps)^2/(8*eps*(1-eps)) > 3 (for P_err < 0.05)

    int N;
    if (eps < 1e-9) {
        // No noise: just need M distinct graphs, minimize N
        N = M + 1;
    } else {
        // Binary search: find smallest N where accuracy is "good enough"
        // With threshold graphs + equal-T-spacing, min Hamming distance ≈ (N-1)/(M-1)
        // (the spacing near k=0 and k=N-1 gives distance N-1-k which is smallest near k=N-2)
        // Actually for linear k spacing (k=0,1,...,M-1), d_min = N - M (distance for k=M-2 vs k=M-1)
        // For good decoding we want: d_min * (1-2*eps)^2 / (4*eps*(1-eps)) > target_exponent
        double target_exp = 4.0; // gives ~98% accuracy per query
        double factor = (1.0 - 2.0 * eps) * (1.0 - 2.0 * eps) / (4.0 * eps * (1.0 - eps));
        if (factor < 1e-9) {
            N = 100; // eps near 0.5, can't do much
        } else {
            int d_min_needed = (int)std::ceil(target_exp / factor);
            d_min_needed = std::max(d_min_needed, 1);
            // With linear k spacing (k = 0, 1, ..., M-1), d_min = N - M
            // So N = M + d_min_needed
            N = M + d_min_needed;
        }
