    // This gives threshold graphs where d(k, k+1) = N - k - 1 >= N - M + 1
    // Alternatively use equal-T-spacing for more uniform Hamming distances
    std::vector<int> k_values(M);

    // Equal-T-spacing gives more uniform Hamming distances
    if (M == 1) {
        k_values[0] = N / 2;
    } else {
        double T_max = (double)(N - 1) * N / 2.0;
        for (int i = 0; i < M; i++) {
            double target_T = (double)i * T_max / (M - 1);
            double disc = (2.0 * N - 1.0) * (2.0 * N - 1.0) - 8.0 * target_T;
