            if (k_values[i] <= k_values[i - 1]) {
                k_values[i] = k_values[i - 1] + 1;
            }
        }
        if (k_values[M - 1] >= N) {
            // Fallback to linear
            for (int i = 0; i < M; i++) {
                k_values[i] = i;
            }
        }
    }

    // Output N and M threshold graphs
    std::cout << N << "\n";
    for (int i = 0; i < M; i++) {
        int k = k_values[i];
        std::string g(L, '0');
        int pos = 0;
        for (int u = 0; u < N; u++) {
            for (int v = u + 1; v < N; v++) {
                if (u < k || v < k) {
                    g[pos] = '1';
                }
                pos++;
            }
        }
        std::cout << g << "\n";
    }
    std::cout.flush();

    // Decode queries
    std::vector<int> deg(N, 0);
    std::vector<int> order(N);

