int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int M;
    double eps;
    std::cin >> M >> eps;

    int N = choose_N(M, eps);
    N = std::max(4, std::min(100, N));
    int L = N * (N - 1) / 2;

    // Select k-values with equal-T-spacing (equidistant in Hamming space)
    std::vector<int> k_values(M);
    if (M == 1) {
        k_values[0] = N / 2;
    } else {
        double T_max = (double)(N - 1) * N / 2.0;
        for (int i = 0; i < M; i++) {
            double target_T = (double)i * T_max / (M - 1);
            double disc = (2.0 * N - 1.0) * (2.0 * N - 1.0) - 8.0 * target_T;
            double k_real = ((2.0 * N - 1.0) - std::sqrt(std::max(0.0, disc))) / 2.0;
            k_values[i] = (int)std::round(k_real);
            k_values[i] = std::max(0, std::min(N - 1, k_values[i]));
        }
        std::sort(k_values.begin(), k_values.end());
        for (int i = 1; i < M; i++) {
            if (k_values[i] <= k_values[i - 1]) k_values[i] = k_values[i - 1] + 1;
        }
        if (k_values[M - 1] >= N) {
            for (int i = 0; i < M; i++) k_values[i] = i;
        }
    }

    // Output threshold graphs
    std::cout << N << "\n";

    // Precompute expected degree sequences for each graph
    // For threshold graph with k hubs:
    //   Hub (vertex i < k): degree = N-1
    //   Non-hub (vertex i >= k): degree = k
    // After noise, expected degrees:
    //   Hub: (N-1)*(1-eps)
    //   Non-hub: k*(1-eps) + (N-1-k)*eps = k - 2*k*eps + (N-1)*eps = k*(1-2eps) + (N-1)*eps

    std::vector<std::vector<double>> expected_deg_sorted(M);
    for (int i = 0; i < M; i++) {
        int k = k_values[i];
        std::string g(L, '0');
        int pos = 0;
        for (int u = 0; u < N; u++) {
            for (int v = u + 1; v < N; v++) {
                if (u < k || v < k) g[pos] = '1';
                pos++;
            }
        }
        std::cout << g << "\n";

        // Expected degree sequence (sorted descending)
        expected_deg_sorted[i].resize(N);
        double hub_deg = (N - 1) * (1.0 - eps);
        double nonhub_deg = k * (1.0 - 2.0 * eps) + (N - 1) * eps;
        for (int j = 0; j < k; j++) expected_deg_sorted[i][j] = hub_deg;
        for (int j = k; j < N; j++) expected_deg_sorted[i][j] = nonhub_deg;
    }
    std::cout.flush();

    // Decode using degree-sequence L2 matching
    std::vector<int> deg(N);
    std::vector<int> deg_sorted(N);

    for (int q = 0; q < 100; q++) {
        std::string h;
        std::cin >> h;

        std::fill(deg.begin(), deg.end(), 0);
        int pos = 0;
        for (int u = 0; u < N; u++) {
            for (int v = u + 1; v < N; v++) {
                if (h[pos] == '1') {
                    deg[u]++;
                    deg[v]++;
                }
                pos++;
            }
        }

        // Sort degrees descending
        std::copy(deg.begin(), deg.end(), deg_sorted.begin());
        std::sort(deg_sorted.begin(), deg_sorted.end(), std::greater<int>());

        // Find graph with minimum L2 distance to sorted degree sequence
        int best = 0;
        double best_dist = 1e18;
        for (int i = 0; i < M; i++) {
            double dist = 0;
            for (int j = 0; j < N; j++) {
                double diff = deg_sorted[j] - expected_deg_sorted[i][j];
                dist += diff * diff;
            }
            if (dist < best_dist) {
                best_dist = dist;
                best = i;
            }
        }

        std::cout << best << "\n";
        std::cout.flush();
    }

    return 0;
}
