        //   N-k non-hubs with expected degree k*(1-2eps) + (N-1)*eps
        //
        // For L2 matching, the signal between k and k+1 (sorted deg seq):
        // The main signal is in the sum of degrees (= 2*edges).
        // Sum of degrees for k-hub: 2 * [k*(2N-k-1)/2] = k*(2N-k-1)
        // After noise: E[sum_deg] = k*(2N-k-1)*(1-2eps) + 2*L*eps = k*(2N-k-1)*(1-2eps) + N*(N-1)*eps
        //
        // Difference in E[sum_deg] between k and k+1:
        //   delta_sum = (1-2eps) * [(k+1)*(2N-k-2) - k*(2N-k-1)]
        //             = (1-2eps) * [2N-k-2 + k*(2N-k-2) - k*(2N-k-1)]
        //             = (1-2eps) * [2N-k-2 - k]
        //             = (1-2eps) * (2N-2k-2)
        //             = (1-2eps) * 2*(N-k-1)
        //
        // Variance of sum_deg: Var(sum_deg) = sum of Var(2*edge_count)
        //   Each edge contributes to 2 degree slots. Var(sum_deg) = 4*L*eps*(1-eps) = 2*N*(N-1)*eps*(1-eps)
        //
        // SNR for k vs k+1 using sum_deg alone:
        //   SNR = delta_sum / sqrt(Var) = (1-2eps)*2*(N-k-1) / sqrt(2*N*(N-1)*eps*(1-eps))
        //
        // Minimum SNR (at k = M-2 for equal-T-spacing, where k is largest):
        //   For equal-T-spacing, the largest k ≈ N*(1-1/sqrt(M-1))
        //   So N-k-1 ≈ N/sqrt(M-1)
        //   SNR_min ≈ (1-2eps)*2*N/sqrt(M-1) / sqrt(2*N*(N-1)*eps*(1-eps))
        //           ≈ (1-2eps)*2*sqrt(N) / (sqrt(2*(M-1)*eps*(1-eps)))
        //
        // With full degree sequence L2 (not just sum): effectively N independent observations
        // The discriminating power is much higher than just using sum.
        // Approximate: P_err ≈ (M-1)*Phi(-SNR/2) where SNR uses the full degree-seq L2 distance.
        //
        // Full deg-seq L2 signal between k and k+1 (sorted):
        //   The vertex that transitions from hub to non-hub loses expected degree (N-1-k)*(1-2eps)
        //   Squared L2 distance ≈ ((N-1-k)*(1-2eps))^2
        //   Noise per degree: Var(deg) = (N-1)*eps*(1-eps)
        //   So SNR^2 ≈ ((N-1-k)*(1-2eps))^2 / ((N-1)*eps*(1-eps))
        //   SNR ≈ (N-1-k)*(1-2eps) / sqrt((N-1)*eps*(1-eps))
        //
        // For equal-T-spacing, min(N-1-k) ≈ N/sqrt(M-1) - 1
        // SNR_min ≈ (N/sqrt(M-1))*(1-2eps) / sqrt((N-1)*eps*(1-eps))
        //         ≈ sqrt(N/(M-1)) * (1-2eps) / sqrt(eps*(1-eps))

        double snr_min;
        if (M <= 2) {
            snr_min = 100.0; // easy
        } else {
            snr_min = std::sqrt((double)N / (M - 1.0)) * (1.0 - 2.0 * eps) / std::sqrt(eps * (1.0 - eps));
        }

        // P_err per query ≈ (M-1) * Phi(-snr_min/2)
        // Phi(-x) ≈ exp(-x^2/2) / (x*sqrt(2*pi)) for large x
        double p_err;
        double x = snr_min / 2.0;
        if (x > 5.0) {
            p_err = 0.0;
        } else if (x > 0) {
            p_err = (M - 1.0) * 0.5 * std::erfc(x / std::sqrt(2.0));
        } else {
            p_err = 1.0;
        }
        p_err = std::min(1.0, std::max(0.0, p_err));

        double expected_errors = 100.0 * p_err;
        double score = std::pow(0.9, expected_errors) / N;

        if (score > best_expected_score) {
            best_expected_score = score;
            best_N = N;
        }
    }

    return best_N;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int M;
    double eps;
    std::cin >> M >> eps;

    int N = choose_N(M, eps);
    N = std::max(4, std::min(100, N));
    int L = N * (N - 1) / 2;

    // Select k-values with equal-T-spacing (equidistant in Hamming space)
    std::vector<int> k_values(M);
    if (M == 1) {
        k_values[0] = N / 2;
    } else {
        double T_max = (double)(N - 1) * N / 2.0;
        for (int i = 0; i < M; i++) {
