    // After noise, expected degrees:
    //   Hub: (N-1)*(1-eps)
    //   Non-hub: k*(1-eps) + (N-1-k)*eps = k - 2*k*eps + (N-1)*eps = k*(1-2eps) + (N-1)*eps

    std::vector<std::vector<double>> expected_deg_sorted(M);
