#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <cmath>
#include <numeric>

// Hamming distance between threshold graphs with k1 and k2 hubs (k1 < k2) in N vertices:
// Positions where they differ: vertex pairs (i,j) where exactly one of i,j is in [k1, k2)
// and the other is in [k2, N) (these are non-hub-non-hub in G_k1 but hub-nonhub in G_k2)
// Plus pairs within [k1, k2) that are non-hub-nonhub in G_k1 but hub-hub in G_k2.
// Actually: G_k has edge (i,j) iff min(i,j) < k.
// G_k1 has edge iff min(i,j) < k1. G_k2 has edge iff min(i,j) < k2.
// They differ when k1 <= min(i,j) < k2, i.e., both i,j >= k1 and at least one < k2 (with min(i,j) < k2).
// More precisely: min(i,j) >= k1 AND min(i,j) < k2
// This means: both i,j >= k1, and min(i,j) < k2.
// = pairs where k1 <= min(i,j) < k2
// = pairs (i,j) with k1 <= i < k2 and j > i (where j can be anything > i, i.e., j in [i+1, N))
// Wait: min(i,j) for i<j is i. So condition: k1 <= i < k2, j > i.
// Count: sum_{i=k1}^{k2-1} (N-1-i) = (k2-k1)*(N-1) - sum_{i=k1}^{k2-1} i
//       = (k2-k1)*(N-1) - (k2-k1)*(k1+k2-1)/2
//       = (k2-k1) * (N - 1 - (k1+k2-1)/2)
//       = (k2-k1) * (2N - 2 - k1 - k2 + 1) / 2
//       = (k2-k1) * (2N - k1 - k2 - 1) / 2

int hamming_dist(int k1, int k2, int N) {
    if (k1 > k2) std::swap(k1, k2);
    return (k2 - k1) * (2 * N - k1 - k2 - 1) / 2;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    int M;
    double eps;
    std::cin >> M >> eps;

    // Search for best N by computing expected score
    int best_N = 4;
    double best_expected_score = -1;

    for (int N = std::max(4, M + 1); N <= 100; N++) {
        int L = N * (N - 1) / 2;

        // Compute k-values with equal-T-spacing
        std::vector<int> kv(M);
        if (M == 1) {
