            }
            if (kv[M - 1] >= N) continue; // Can't fit M values
        }

        // Find minimum Hamming distance
        int d_min = L;
        for (int i = 0; i < M - 1; i++) {
            int d = hamming_dist(kv[i], kv[i + 1], N);
            d_min = std::min(d_min, d);
        }

        // P(error) for edge-disagreement decoder with perfect alignment:
        // For correct graph (distance 0): mismatch ~ Binomial(L, eps), mean = L*eps
        // For wrong graph at distance d: mismatch ~ Binomial(L-d, eps) + Binomial(d, 1-eps)
        //   mean = (L-d)*eps + d*(1-eps) = L*eps + d*(1-2*eps)
        // Difference in means = d*(1-2*eps), combined variance ≈ 2*L*eps*(1-eps)
        // But with degree-based alignment (not perfect), effective distance is reduced.
        // Empirically the alignment quality is high for threshold graphs.
        // Use a conservative factor of 0.7 for alignment quality.
        double align_factor = 0.7;
        double effective_d = d_min * align_factor;

        double signal = effective_d * (1.0 - 2.0 * eps);
        double noise_std = std::sqrt(2.0 * L * eps * (1.0 - eps));

        double p_err;
        if (eps < 1e-9) {
            p_err = 0.0;
        } else if (noise_std < 1e-9) {
            p_err = (signal > 0) ? 0.0 : 1.0;
        } else {
            double z = signal / noise_std;
            p_err = (M - 1.0) * 0.5 * std::erfc(z / std::sqrt(2.0));
            p_err = std::min(1.0, p_err);
        }

        double expected_errors = 100.0 * p_err;
        double score = std::pow(0.9, expected_errors) / N;

        if (score > best_expected_score) {
            best_expected_score = score;
            best_N = N;
        }
    }

    int N = best_N;
    int L = N * (N - 1) / 2;

    // Compute k-values with equal-T-spacing
    std::vector<int> k_values(M);
    if (M == 1) {
        k_values[0] = N / 2;
    } else {
        double T_max = (double)(N - 1) * N / 2.0;
        for (int i = 0; i < M; i++) {
            double target_T = (double)i * T_max / (M - 1);
            double disc = (2.0 * N - 1.0) * (2.0 * N - 1.0) - 8.0 * target_T;
            double k_real = ((2.0 * N - 1.0) - std::sqrt(std::max(0.0, disc))) / 2.0;
            k_values[i] = (int)std::round(k_real);
            k_values[i] = std::max(0, std::min(N - 1, k_values[i]));
        }
        std::sort(k_values.begin(), k_values.end());
        for (int i = 1; i < M; i++) {
            if (k_values[i] <= k_values[i - 1]) k_values[i] = k_values[i - 1] + 1;
        }
        if (k_values[M - 1] >= N) {
            for (int i = 0; i < M; i++) k_values[i] = i;
        }
    }

    // Output threshold graphs
    std::cout << N << "\n";
    for (int i = 0; i < M; i++) {
        int k = k_values[i];
        std::string g(L, '0');
        int pos = 0;
        for (int u = 0; u < N; u++) {
            for (int v = u + 1; v < N; v++) {
                if (u < k || v < k) g[pos] = '1';
                pos++;
            }
        }
        std::cout << g << "\n";
    }
    std::cout.flush();

    // Decode using edge-disagreement with degree-based alignment
    std::vector<int> deg(N);
    std::vector<int> order(N);
    std::vector<std::vector<bool>> adj(N, std::vector<bool>(N, false));

    for (int q = 0; q < 100; q++) {
        std::string h;
        std::cin >> h;

        std::fill(deg.begin(), deg.end(), 0);
        int E_H = 0;
        int pos = 0;
        for (int u = 0; u < N; u++) {
            for (int v = u + 1; v < N; v++) {
                bool e = (h[pos] == '1');
                adj[u][v] = adj[v][u] = e;
                if (e) { deg[u]++; deg[v]++; E_H++; }
                pos++;
            }
