        for (int j = 0; j < N; j++) {
            for (int j2 = j + 1; j2 < N; j2++) {
                if (adj[order[j]][order[j2]]) deg_in_suffix[j]++;
            }
        }

        std::vector<int> E_out(N + 1, 0);
        E_out[0] = E_H;
        for (int k = 1; k <= N; k++) {
            E_out[k] = E_out[k - 1] - deg_in_suffix[k - 1];
        }

        // Find best match: minimize mismatches = k*(2N-k-1)/2 - E_H + 2*E_out[k]
        int best = 0;
        int best_mismatch = L + 1;
        for (int i = 0; i < M; i++) {
            int k = k_values[i];
            int mismatches = k * (2 * N - k - 1) / 2 - E_H + 2 * E_out[k];
            if (mismatches < best_mismatch) {
                best_mismatch = mismatches;
                best = i;
            }
        }

        std::cout << best << "\n";
        std::cout.flush();
    }

    return 0;
