    // Positions k2..N-1: G_k2 non-hub (k2*(1-2eps)+(N-1)*eps), G_k1 non-hub (k1*(1-2eps)+(N-1)*eps)
    //   diff = (k2-k1)*(1-2eps)
    //
    // Squared L2 = (k2-k1)*[(N-1-k1)*(1-2eps)]^2 + (N-k2)*[(k2-k1)*(1-2eps)]^2
    //            = (1-2eps)^2 * [(k2-k1)*(N-1-k1)^2 + (N-k2)*(k2-k1)^2]
    //            = (1-2eps)^2 * (k2-k1) * [(N-1-k1)^2 + (N-k2)*(k2-k1)]
