        int best = 0;
        int best_mismatch = L + 1;
        for (int i = 0; i < M; i++) {
            int k = k_values[i];
            int mismatches = k * (2 * N - k - 1) / 2 - E_H + 2 * E_out[k];
            if (mismatches < best_mismatch) {
                best_mismatch = mismatches;
                best = i;
            }
        }

