        int pos = 0;
        for (int u = 0; u < N; u++) {
            for (int v = u + 1; v < N; v++) {
                if (u < k || v < k) g[pos] = '1';
                pos++;
            }
        }
        std::cout << g << "\n";
    }
    std::cout.flush();

    // Decode using edge-disagreement with degree-based alignment + local search
    std::vector<int> deg(N);
    std::vector<int> order(N);
    std::vector<std::vector<bool>> adj(N, std::vector<bool>(N, false));

